import { useState } from "react";
import {
  Box,
  Typography,
  TextField,
  Button,
  Paper,
  Table,
  TableHead,
  TableRow,
  TableCell,
  TableBody,
  IconButton,
} from "@mui/material";
import { Edit, Delete } from "@mui/icons-material";

export default function ProjectManagement() {
  const [search, setSearch] = useState("");

  const data = [
    {
      id: 1,
      project_name: "BIM Alignment",
      user: "Deepika",
      description: "Reality sync system ",
      start: "01-05-2025",
      end: "30-05-2025",
      joined: "21-05-2025",
    },
    {
      id: 2,
      project_name: "3D Web Viewer",
      user: "Raghul",
      description: "Web visualization",
      start: "01-10-2025",
      end: "30-10-2025",
      joined: "20-10-2025",
    },
  ];

  return (
    <Box sx={{ p: 4, display: "flex", justifyContent: "center" }}>
      <Paper
        elevation={12}
        sx={{
          width: "100%",
          maxWidth: 1200,
          p: 4,
          borderRadius: "20px",
          background: "linear-gradient(145deg, #f0f0f0, #ffffff)",
          boxShadow: "20px 20px 60px #d9d9d9, -20px -20px 60px #ffffff",
        }}
      >
        {/* 🔹 HEADER */}
        <Box
          sx={{
            display: "flex",
            justifyContent: "space-between",
            mb: 3,
          }}
        >
          <Typography variant="h5" fontWeight="bold">
            Project Management
          </Typography>

          <Button
            variant="contained"
            sx={{
              borderRadius: "12px",
              background: "linear-gradient(135deg, #1976d2, #42a5f5)",
              boxShadow: "0px 4px 15px rgba(0,0,0,0.2)",
            }}
          >
            + Add User
          </Button>
        </Box>

        {/* 🔍 SEARCH */}
        <TextField
          fullWidth
          placeholder="Search..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          sx={{
            mb: 3,
            "& .MuiOutlinedInput-root": {
              borderRadius: "12px",
              background: "#fff",
              boxShadow: "inset 2px 2px 6px #d1d1d1",
            },
          }}
        />

        {/* 📊 TABLE */}
        <Paper
          sx={{
            borderRadius: "15px",
            overflow: "auto",
            boxShadow: "inset 3px 3px 8px #d1d1d1, inset -3px -3px 8px #ffffff",
          }}
        >
          <Table>
            <TableHead>
              <TableRow
                sx={{
                  background: "linear-gradient(135deg, #1976d2, #42a5f5)",
                }}
              >
                {[
                  "Project Name",
                  "User Name",
                  "Description",
                  "Start Date",
                  "End Date",
                  "Joined Date",
                  "Actions",
                ].map((head) => (
                  <TableCell key={head} sx={{ color: "#fff" }}>
                    <b>{head}</b>
                  </TableCell>
                ))}
              </TableRow>
            </TableHead>

            <TableBody>
              {data
                .filter((d) =>
                  d.project_name.toLowerCase().includes(search.toLowerCase()),
                )
                .map((row) => (
                  <TableRow
                    key={row.id}
                    sx={{
                      transition: "0.3s",
                      "&:hover": {
                        background: "#f5faff",
                        transform: "scale(1.01)",
                      },
                    }}
                  >
                    <TableCell>{row.project_name}</TableCell>
                    <TableCell>{row.user}</TableCell>
                    <TableCell>{row.description}</TableCell>
                    <TableCell>{row.start}</TableCell>
                    <TableCell>{row.end}</TableCell>
                    <TableCell>{row.joined}</TableCell>

                    <TableCell>
                      <IconButton
                        sx={{
                          color: "#1976d2",
                          "&:hover": { background: "#e3f2fd" },
                        }}
                      >
                        <Edit />
                      </IconButton>

                      <IconButton
                        sx={{
                          color: "#d32f2f",
                          "&:hover": { background: "#ffebee" },
                        }}
                      >
                        <Delete />
                      </IconButton>
                    </TableCell>
                  </TableRow>
                ))}
            </TableBody>
          </Table>
        </Paper>
      </Paper>
    </Box>
  );
}
